package br.edu.atitus.mathias_karling_stadtlober.zoo_digital.animais; import br.edu.atitus.mathias_karling_stadtlober.zoo_digital.comportamentos.*; import br.edu.atitus.mathias_karling_stadtlober.zoo_digital.especies.Mamifero; public class Gato extends Mamifero implements Corrida, Predacao { public Gato(String nome, int idade) { super(nome, idade); } public void emitirSom() { System.out.println(getNome() + " mia: miau!"); } public void comer() { System.out.println(getNome() + " está comendo peixe."); } public void correr() { System.out.println(getNome() + " está correndo silenciosamente."); } public void cacar() { System.out.println(getNome() + " está caçando um brinquedo como se fosse presa."); } }
